action.script:

import com.liferay.portal.kernel.util.GetterUtil;
import com.liferay.portal.kernel.workflow.WorkflowConstants;
import com.liferay.portal.kernel.workflow.WorkflowStatusManagerUtil;
import com.liferay.portal.kernel.model.User;
import com.liferay.portal.workflow.kaleo.service.KaleoLogLocalServiceUtil;

WorkflowStatusManagerUtil.updateStatus(WorkflowConstants.STATUS_APPROVED, workflowContext);

kaleoLog = KaleoLogLocalServiceUtil.addNodeExitKaleoLog(kaleoInstanceToken, kaleoInstanceToken.getCurrentKaleoNode(), serviceContext);

kaleoLog.setCurrentAssigneeClassName(User.class.getName());
kaleoLog.setCurrentAssigneeClassPK(GetterUtil.getLong(userId));
kaleoLog.setPreviousKaleoNodeName("review");

KaleoLogLocalServiceUtil.updateKaleoLog(kaleoLog);


import com.liferay.portal.kernel.model.User;
import com.liferay.portal.kernel.util.GetterUtil;
import com.liferay.portal.workflow.kaleo.service.KaleoLogLocalServiceUtil;

kaleoLog = KaleoLogLocalServiceUtil.addNodeExitKaleoLog(kaleoInstanceToken, kaleoInstanceToken.getCurrentKaleoNode(), serviceContext);

kaleoLog.setCurrentAssigneeClassName(User.class.getName());
kaleoLog.setCurrentAssigneeClassPK(GetterUtil.getLong(userId));
kaleoLog.setPreviousKaleoNodeName("review");

KaleoLogLocalServiceUtil.updateKaleoLog(kaleoLog);


import com.liferay.portal.kernel.util.GetterUtil;
import com.liferay.portal.kernel.workflow.WorkflowStatusManagerUtil;
import com.liferay.portal.kernel.model.User;
import com.liferay.portal.workflow.kaleo.service.KaleoLogLocalServiceUtil;

WorkflowStatusManagerUtil.updateStatus(500, workflowContext);

kaleoLog = KaleoLogLocalServiceUtil.addNodeExitKaleoLog(kaleoInstanceToken, kaleoInstanceToken.getCurrentKaleoNode(), serviceContext);

kaleoLog.setCurrentAssigneeClassName(User.class.getName());
kaleoLog.setCurrentAssigneeClassPK(GetterUtil.getLong(userId));
kaleoLog.setPreviousKaleoNodeName("review");

KaleoLogLocalServiceUtil.updateKaleoLog(kaleoLog);


import com.liferay.portal.kernel.search.Indexer;
import com.liferay.portal.kernel.search.IndexerRegistryUtil;
import com.liferay.portal.kernel.util.GetterUtil;
import com.liferay.portal.kernel.workflow.WorkflowTask;
import com.liferay.portal.kernel.workflow.WorkflowTaskManagerUtil;

WorkflowTask workflowTask = WorkflowTaskManagerUtil.getWorkflowTask(GetterUtil.getLong(companyId), kaleoTaskInstanceToken.getKaleoTaskInstanceTokenId());

Indexer indexer = IndexerRegistryUtil.getIndexer(WorkflowTask.class.getName());

indexer.reindex(workflowTask);

scripted-assignment.script:

import com.liferay.portal.kernel.util.GetterUtil;
import com.liferay.portal.kernel.workflow.WorkflowConstants;
import com.liferay.portal.kernel.model.Role;
import com.liferay.portal.kernel.service.RoleLocalServiceUtil;
import com.liferay.portal.kernel.service.UserLocalServiceUtil;

import java.util.ArrayList;

long companyId = GetterUtil.getLong(workflowContext.get(WorkflowConstants.CONTEXT_COMPANY_ID));
String supportRegionName = (String)workflowContext.get("osbSupportRegionName");

roles = new ArrayList<Role>();

Role role = RoleLocalServiceUtil.fetchRole(companyId, supportRegionName + " Provisioning Reviewer");

if (role != null) {
	roles.add(role);
}

if (roles.isEmpty()) {
	role = RoleLocalServiceUtil.getRole(companyId, "Global Provisioning Reviewer");

	roles.add(role);
}

user = null;
